// ─── Types ────────────────────────────────────────────────────────────────────

export type Category =
  | "all"
  | "mindset"
  | "relationships"
  | "career"
  | "self-love"
  | "anxiety"
  | "motivation"
  | "healing";

export interface Author {
  name: string;
  title: string; // e.g. "Roman Emperor", "Poet", "Entrepreneur"
  era: string;   // e.g. "121–180 AD", "1856–1939"
  nationality: string;
  initials: string;
  color: string; // tailwind bg class for avatar
}

export interface Quote {
  id: number;
  text: string;
  author: Author;
  category: Exclude<Category, "all">;
  timestamp?: number;
}

